@js:
var inputData = `榜单
排行榜::/paihang/{{page}}.html
完结小说::/wanjie/{{page}}.html
小说分类
都市小说::/dushi/{{page}}.html
玄幻小说::/xuanhuan/{{page}}.html
轻小说::/qing/{{page}}.html
仙侠小说::/xianxia/{{page}}.html
历史小说::/lishi/{{page}}.html
科幻小说::/kehuan/{{page}}.html
诸天无限::/zhutianwuxian/{{page}}.html
游戏小说::/youxi/{{page}}.html
奇幻小说::/qihuan/{{page}}.html
悬疑小说::/xuanyi/{{page}}.html
体育小说::/tiyu/{{page}}.html
官场小说::/guanchang/{{page}}.html
军事小说::/junshi/{{page}}.html
武侠小说::/wuxia/{{page}}.html
乡村小说::/xiangcun/{{page}}.html
现实小说::/xianshi/{{page}}.html
言情小说::/yanqing/{{page}}.html`;

var categories = [];
var lines = inputData.split('\n').filter(l => l.trim());

for (var i = 0; i < lines.length; i++) {
    var parts = lines[i].split('::');
    var title = parts[0] || "";
    var url = (parts[1] || "").trim();

    categories.push({
        "title": title,
        "url": url,
        "style": {
            "layout_flexGrow": 1,
            "layout_flexBasisPercent": url ? 0.25 : 1
        }
    });
}

JSON.stringify(categories);
